import{_ as e,o as s,c as r,a2 as t}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"考研真相","description":"","frontmatter":{"title":"考研真相","author":"","collection":"职场成长","series_order":6,"total_chars":1586},"headers":[],"relativePath":"career/grad-school-truth.md","filePath":"career/grad-school-truth.md"}'),o={name:"career/grad-school-truth.md"};function h(l,a,n,i,d,c){return s(),r("div",null,[...a[0]||(a[0]=[t('<div class="page-toc"><p class="page-toc-title">📑 本页目录</p><a href="#s-417" class="page-toc-link">考研真相系列</a>     <a href="#s-418" class="page-toc-link">上岸必看，没人告诉你的10个考研真相（开篇）</a>     <a href="#s-422" class="page-toc-link">上岸必看，没人告诉你的10个考研真相｜坑一：用力过猛</a>     <a href="#s-428" class="page-toc-link">上岸必看，没人告诉你的10个考研真相｜坑二：不切实际的定位</a>     <a href="#s-433" class="page-toc-link">上岸必看，没人告诉你的10个考研真相｜坑三&amp;坑四</a>     <a href="#s-438" class="page-toc-link">上岸必看，没人告诉你的10个考研真相（下）｜动态计划与普通人假设</a>     <a href="#s-443" class="page-toc-link">上岸必看，没人告诉你的10个考研真相（下）｜隔绝手机与励志书法</a>     <a href="#s-448" class="page-toc-link">上岸必看，没人告诉你的10个考研真相（下）｜反文具主义</a></div><h2 id="s-417" tabindex="-1">考研真相系列 <a class="header-anchor" href="#s-417" aria-label="Permalink to &quot;考研真相系列 {#s-417}&quot;">​</a></h2><p>共7个视频</p><h3 id="s-418" tabindex="-1">上岸必看，没人告诉你的10个考研真相（开篇） <a class="header-anchor" href="#s-418" aria-label="Permalink to &quot;上岸必看，没人告诉你的10个考研真相（开篇） {#s-418}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-419" tabindex="-1">1. 考研像在漆黑屋子里洗衣服，不到开门那刻不知道结果 <a class="header-anchor" href="#s-419" aria-label="Permalink to &quot;1. 考研像在漆黑屋子里洗衣服，不到开门那刻不知道结果 {#s-419}&quot;">​</a></h4><h4 id="s-420" tabindex="-1">2. 也像蒙眼拉磨——永远不知道别人往里放了多少豆子 <a class="header-anchor" href="#s-420" aria-label="Permalink to &quot;2. 也像蒙眼拉磨——永远不知道别人往里放了多少豆子 {#s-420}&quot;">​</a></h4><h4 id="s-421" tabindex="-1">3. 坚持到最后一刻才能见分晓，人生处处如考研 <a class="header-anchor" href="#s-421" aria-label="Permalink to &quot;3. 坚持到最后一刻才能见分晓，人生处处如考研 {#s-421}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「考研特别像是在漆黑一片什么都看不到的屋子里面洗衣服，一直到最后拉开门的那一刹那，你才知道你洗得如何」</em></p><p><strong>行动指南</strong></p><p>坚持到最后一刻不要放弃，保持信念</p><h3 id="s-422" tabindex="-1">上岸必看，没人告诉你的10个考研真相｜坑一：用力过猛 <a class="header-anchor" href="#s-422" aria-label="Permalink to &quot;上岸必看，没人告诉你的10个考研真相｜坑一：用力过猛 {#s-422}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-423" tabindex="-1">1. 坑一：用力过猛自我感动——读外刊精读、从教材开始系统复习，效率极低 <a class="header-anchor" href="#s-423" aria-label="Permalink to &quot;1. 坑一：用力过猛自我感动——读外刊精读、从教材开始系统复习，效率极低 {#s-423}&quot;">​</a></h4><h4 id="s-424" tabindex="-1">2. 真题就是最好的复习资料，考研应查漏补缺定向爆破，而非事无巨细面面俱到 <a class="header-anchor" href="#s-424" aria-label="Permalink to &quot;2. 真题就是最好的复习资料，考研应查漏补缺定向爆破，而非事无巨细面面俱到 {#s-424}&quot;">​</a></h4><h4 id="s-425" tabindex="-1">3. 培训机构延长课时是商业手段（外刊精读=增加产品售卖），不是有效学习方式 <a class="header-anchor" href="#s-425" aria-label="Permalink to &quot;3. 培训机构延长课时是商业手段（外刊精读=增加产品售卖），不是有效学习方式 {#s-425}&quot;">​</a></h4><h4 id="s-426" tabindex="-1">4. 形式上的精美笔记和仪式感学习是一种自我安慰 <a class="header-anchor" href="#s-426" aria-label="Permalink to &quot;4. 形式上的精美笔记和仪式感学习是一种自我安慰 {#s-426}&quot;">​</a></h4><h4 id="s-427" tabindex="-1">5. 先把必考必会的东西弄懂，再做延伸 <a class="header-anchor" href="#s-427" aria-label="Permalink to &quot;5. 先把必考必会的东西弄懂，再做延伸 {#s-427}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「真题就是最好的复习资料」</em></p><p><strong>行动指南</strong></p><p>先做真题抓核心考点，不要在外围知识上浪费时间自我感动</p><h3 id="s-428" tabindex="-1">上岸必看，没人告诉你的10个考研真相｜坑二：不切实际的定位 <a class="header-anchor" href="#s-428" aria-label="Permalink to &quot;上岸必看，没人告诉你的10个考研真相｜坑二：不切实际的定位 {#s-428}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-429" tabindex="-1">1. 坑二：不切实际的定位——专科生非要考C9理工科，普信考研人问题严重 <a class="header-anchor" href="#s-429" aria-label="Permalink to &quot;1. 坑二：不切实际的定位——专科生非要考C9理工科，普信考研人问题严重 {#s-429}&quot;">​</a></h4><h4 id="s-430" tabindex="-1">2. 人生最大突破之一是承认自己是普通人 <a class="header-anchor" href="#s-430" aria-label="Permalink to &quot;2. 人生最大突破之一是承认自己是普通人 {#s-430}&quot;">​</a></h4><h4 id="s-431" tabindex="-1">3. 选校两个标准：上一届有活人考上了你想去的学校；选招相对多的专业 <a class="header-anchor" href="#s-431" aria-label="Permalink to &quot;3. 选校两个标准：上一届有活人考上了你想去的学校；选招相对多的专业 {#s-431}&quot;">​</a></h4><h4 id="s-432" tabindex="-1">4. 不要指望自己成为第一人或最幸运的人 <a class="header-anchor" href="#s-432" aria-label="Permalink to &quot;4. 不要指望自己成为第一人或最幸运的人 {#s-432}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「我人生的一个非常大的突破，是我发现了我是一个普通人」</em></p><p><strong>行动指南</strong></p><p>用&quot;普通人假设&quot;定位目标院校，参考学长学姐真实上岸数据选校</p><h3 id="s-433" tabindex="-1">上岸必看，没人告诉你的10个考研真相｜坑三&amp;坑四 <a class="header-anchor" href="#s-433" aria-label="Permalink to &quot;上岸必看，没人告诉你的10个考研真相｜坑三&amp;坑四 {#s-433}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **坑三：精神内耗——选择太少导致内耗，既没准备出国也没offer，考研成了唯一</p><h4 id="s-434" tabindex="-1">2. 内耗时多想将来少想现在，多想上岸少想失败 <a class="header-anchor" href="#s-434" aria-label="Permalink to &quot;2. 内耗时多想将来少想现在，多想上岸少想失败 {#s-434}&quot;">​</a></h4><h4 id="s-435" tabindex="-1">3. 坑四：闭门造车——普通家庭孩子因羞耻心不敢请教成功者，越差啥越不敢问啥 <a class="header-anchor" href="#s-435" aria-label="Permalink to &quot;3. 坑四：闭门造车——普通家庭孩子因羞耻心不敢请教成功者，越差啥越不敢问啥 {#s-435}&quot;">​</a></h4><h4 id="s-436" tabindex="-1">4. 善良的人更不好意思麻烦别人，但你有自己的价值可以回报他人 <a class="header-anchor" href="#s-436" aria-label="Permalink to &quot;4. 善良的人更不好意思麻烦别人，但你有自己的价值可以回报他人 {#s-436}&quot;">​</a></h4><h4 id="s-437" tabindex="-1">5. 这个社会是流动的，没有一个人是一座孤岛 <a class="header-anchor" href="#s-437" aria-label="Permalink to &quot;5. 这个社会是流动的，没有一个人是一座孤岛 {#s-437}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「选择太少会带来精神内耗」</em></p><p><strong>行动指南</strong></p><p>多准备备选方案减少内耗，主动请教成功者获取正确经验</p><h3 id="s-438" tabindex="-1">上岸必看，没人告诉你的10个考研真相（下）｜动态计划与普通人假设 <a class="header-anchor" href="#s-438" aria-label="Permalink to &quot;上岸必看，没人告诉你的10个考研真相（下）｜动态计划与普通人假设 {#s-438}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **解决方案一：动态计划——计划前期作用是验证真实效率，然后根据效率调整大计划</p><h4 id="s-439" tabindex="-1">2. 看一个人段位高低，不是看他多做什么，而是看他不做什么 <a class="header-anchor" href="#s-439" aria-label="Permalink to &quot;2. 看一个人段位高低，不是看他多做什么，而是看他不做什么 {#s-439}&quot;">​</a></h4><h4 id="s-440" tabindex="-1">3. 普通人假设：承认自己是普通人，不要把自己当赛亚人 <a class="header-anchor" href="#s-440" aria-label="Permalink to &quot;3. 普通人假设：承认自己是普通人，不要把自己当赛亚人 {#s-440}&quot;">​</a></h4><h4 id="s-441" tabindex="-1">4. 英雄主义叙事让你活在虚构世界，最终与真实碰撞时崩溃 <a class="header-anchor" href="#s-441" aria-label="Permalink to &quot;4. 英雄主义叙事让你活在虚构世界，最终与真实碰撞时崩溃 {#s-441}&quot;">​</a></h4><h4 id="s-442" tabindex="-1">5. 分合温吞的努力比一时热血的冲刺更有效 <a class="header-anchor" href="#s-442" aria-label="Permalink to &quot;5. 分合温吞的努力比一时热血的冲刺更有效 {#s-442}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「看一个人段位高低，不是看他多做什么，而是看他不做什么」</em></p><p><strong>行动指南</strong></p><p>制定动态计划验证真实效率，用普通人假设给自己减负</p><h3 id="s-443" tabindex="-1">上岸必看，没人告诉你的10个考研真相（下）｜隔绝手机与励志书法 <a class="header-anchor" href="#s-443" aria-label="Permalink to &quot;上岸必看，没人告诉你的10个考研真相（下）｜隔绝手机与励志书法 {#s-443}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-444" tabindex="-1">1. 隔绝手机是第一步——有活人把手机放宿舍一整年，一年通过法考+CPA六门 <a class="header-anchor" href="#s-444" aria-label="Permalink to &quot;1. 隔绝手机是第一步——有活人把手机放宿舍一整年，一年通过法考+CPA六门 {#s-444}&quot;">​</a></h4><h4 id="s-445" tabindex="-1">2. 励志书法：学不下去时翻励志书充电，等励志书看腻了学习就成了新鲜事 <a class="header-anchor" href="#s-445" aria-label="Permalink to &quot;2. 励志书法：学不下去时翻励志书充电，等励志书看腻了学习就成了新鲜事 {#s-445}&quot;">​</a></h4><h4 id="s-446" tabindex="-1">3. 利用人性求新本能：让学习变成你环境中&quot;最新&quot;的东西 <a class="header-anchor" href="#s-446" aria-label="Permalink to &quot;3. 利用人性求新本能：让学习变成你环境中&quot;最新&quot;的东西 {#s-446}&quot;">​</a></h4><h4 id="s-447" tabindex="-1">4. 隔绝手机+励志书+学习形成良性正循环 <a class="header-anchor" href="#s-447" aria-label="Permalink to &quot;4. 隔绝手机+励志书+学习形成良性正循环 {#s-447}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「失去手机你会获得人生的成就」</em></p><p><strong>行动指南</strong></p><p>学习时锁手机，用励志书做过渡充电工具，让学习成为环境中最新鲜的事</p><h3 id="s-448" tabindex="-1">上岸必看，没人告诉你的10个考研真相（下）｜反文具主义 <a class="header-anchor" href="#s-448" aria-label="Permalink to &quot;上岸必看，没人告诉你的10个考研真相（下）｜反文具主义 {#s-448}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-449" tabindex="-1">1. 学习核心工具：计划量表、番茄时钟、干净桌子、手机锁 <a class="header-anchor" href="#s-449" aria-label="Permalink to &quot;1. 学习核心工具：计划量表、番茄时钟、干净桌子、手机锁 {#s-449}&quot;">​</a></h4><h4 id="s-450" tabindex="-1">2. 反文具主义——精美笔记和七彩笔是浪费时间和自我安慰 <a class="header-anchor" href="#s-450" aria-label="Permalink to &quot;2. 反文具主义——精美笔记和七彩笔是浪费时间和自我安慰 {#s-450}&quot;">​</a></h4><h4 id="s-451" tabindex="-1">3. 考研是干净的事，核心就是按计划做题 <a class="header-anchor" href="#s-451" aria-label="Permalink to &quot;3. 考研是干净的事，核心就是按计划做题 {#s-451}&quot;">​</a></h4><h4 id="s-452" tabindex="-1">4. 过多工具和仪式感是干扰，让人在外围游荡而不做真正重要的事 <a class="header-anchor" href="#s-452" aria-label="Permalink to &quot;4. 过多工具和仪式感是干扰，让人在外围游荡而不做真正重要的事 {#s-452}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「考研本身是一个很干净的事」</em></p><p><strong>行动指南</strong></p><p>去除多余工具和仪式感，保留核心学习工具，专注做题本身</p>',75)])])}const q=e(o,[["render",h]]);export{u as __pageData,q as default};
